def predict(events):
    om = dict(wp="a", wq="A", kx="b", kz="B")
    pair = dict(a="A", b="B")
    s = [om[e["type"]] for e in events if e["type"] in om]
    st = []
    md = 0
    na = 0
    nb = 0
    for x in s:
        if x == "a" or x == "b":
            if x == "a":
                na += 1
            else:
                nb += 1
            st.append(x)
            if len(st) > md:
                md = len(st)
        else:
            if (not st) or pair[st[-1]] != x:
                return "reject"
            st.pop()
    if st:
        return "reject"
    if na == nb and md == 3:
        return "accept"
    return "reject"
